#include<bits/stdc++.h>
using namespace std;
int n,a[100],sc[100];
void shuchu()
{
	int i;
    for(i=1;i<=n;i++)
   		printf("%5d",sc[i]);
    printf("\n");
    return;
}
void dfs(int k)
{

    if(k==n)
    {	
		shuchu();
        return;
    }
    for(int i=1;i<=n;i++)
    {
        if(a[i]==0)
        {
            a[i]=1;
            sc[k+1]=i;
            dfs(k+1);
            a[i]=0;
        }
    }
}
int main()
{
    scanf("%d",&n); 
    dfs(0);
    return 0;
}
